mapper.insert:
INSERT INTO sb_trade_info ( member_seller_seq, sale_title, book_img, book_title, book_author, book_publisher, book_org_price, isbn, category_nm, category_seq, book_st, payment_type, sale_cont, sale_price, delivery_cost,
sale_rg ,
crt_dtm ) VALUES ( #{member_seller_seq}, #{sale_title}, #{book_img}, #{book_title}, #{book_author}, #{book_publisher}, #{book_org_price}, #{isbn}, #{category_nm}, #{category_seq}, #{book_st}, #{payment_type}, #{sale_cont}, #{sale_price}, #{delivery_cost}
, #{sale_rg}
, now() )

mapper.select:
SELECT pending_buyer_seq
FROM sb_trade_info
WHERE trade_seq = #{trade_seq}

mapper.update:
UPDATE sb_trade_info
SET del_dtm = now()
WHERE trade_seq = #{trade_seq}

mapper.select:
SELECT ti.trade_seq, ti.book_title, ti.book_author, ti.book_publisher, ti.book_img, ti.sale_title, ti.sale_price, ti.sale_st, ti.sale_rg, ti.crt_dtm, COALESCE(tl.wish_count, 0) AS wish_count FROM sb_trade_info ti LEFT JOIN ( SELECT trade_seq, COUNT(*) AS wish_count FROM trade_wish GROUP BY trade_seq ) tl ON ti.trade_seq = tl.trade_seq WHERE ti.del_dtm IS NULL
AND ti.category_seq = #{searchVO.category_seq}
AND ti.book_st = #{searchVO.book_st}
AND ( ti.book_title LIKE CONCAT('%', #{searchVO.search_word}, '%') OR ti.sale_title LIKE CONCAT('%', #{searchVO.search_word}, '%') OR ti.book_author LIKE CONCAT('%', #{searchVO.search_word}, '%') OR ti.book_publisher LIKE CONCAT('%', #{searchVO.search_word}, '%') )
AND ti.sale_st = #{searchVO.sale_st}
ORDER BY ti.sale_price ASC
ORDER BY wish_count DESC
ORDER BY ti.crt_dtm DESC
LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*)
FROM sb_trade_info
WHERE
    del_dtm IS NULL 


    AND category_seq = #{searchVO.category_seq}


    AND book_st = #{searchVO.book_st}


    AND (
        book_title LIKE CONCAT('%', #{searchVO.search_word}, '%')
        OR sale_title LIKE CONCAT('%', #{searchVO.search_word}, '%')
        OR book_author LIKE CONCAT('%', #{searchVO.search_word}, '%')
        OR book_publisher LIKE CONCAT('%', #{searchVO.search_word}, '%')
    )



    AND sale_st = #{searchVO.sale_st}

SELECT COUNT(*)
FROM trade_wish
WHERE trade_seq = #{trade_seq} AND member_seq = #{member_seq}

SELECT COUNT(*)
FROM trade_wish
WHERE trade_seq = #{trade_seq}

mapper.update:
UPDATE sb_trade_info
SET del_dtm = now()
WHERE member_seller_seq = #{member_seq}

mapper.select:
SELECT T.TRADE_SEQ , T.SALE_TITLE , T.SALE_PRICE , T.SALE_ST , T.BOOK_ST , T.SALE_RG , T.SALE_ST_DTM , T.CRT_DTM , T.BOOK_IMG , T.SAFE_PAYMENT_ST , T.POST_NO , T.ADDR_H , T.ADDR_D , T.SETTLEMENT_ST , T.DELIVERY_COST FROM sb_trade_info T WHERE T.MEMBER_SELLER_SEQ = #{member_seq} AND T.DEL_DTM IS NULL
AND T.SALE_ST = #{status}
ORDER BY T.CRT_DTM DESC

SELECT COALESCE(safe_payment_st, 'NONE')
FROM sb_trade_info
WHERE trade_seq = #{trade_seq}

mapper.update:
UPDATE sb_trade_info
SET SALE_ST = #{saleStatus}
WHERE trade_seq = #{trade_seq}
